export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

export interface ThemeColorTokens {
  /** Page/app background */
  background: string;
  /** Default text color */
  foreground: string;
  /** Interactive accent / primary brand color (oklch) */
  accent: string;
  /** Sidebar panel background */
  sidebarBg: string;
  /** Code editor panel background */
  editorBg: string;
  /** Integrated terminal background */
  terminalBg: string;
  /** Status bar background */
  statusBarBg: string;
  /** Status bar foreground */
  statusBarFg: string;
  /** Whether this theme is considered dark (controls .dark class) */
  dark: boolean;
}

export interface BuiltInTheme {
  id: ThemeId;
  label: string;
  tokens: ThemeColorTokens;
}

export const BUILT_IN_THEMES: readonly BuiltInTheme[] = [
  {
    id: "t3-dark",
