import { useCallback, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES,
  type BuiltInTheme,
  type ThemeId,
  getBuiltInTheme,
  isThemeId,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:custom-theme";
const DEFAULT_THEME_ID: ThemeId = "t3-dark";

let listeners: Array<() => void> = [];
let lastThemeId: ThemeId | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredThemeId(): ThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  return isThemeId(raw) ? raw : DEFAULT_THEME_ID;
}

function applyCustomTheme(themeId: ThemeId, suppressTransitions = false) {
  const theme = getBuiltInTheme(themeId);
  const { tokens } = theme;

  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Set the data-theme attribute for CSS custom property overrides
  document.documentElement.setAttribute("data-theme", themeId);

  // Toggle .dark class for Tailwind dark variant compatibility
  document.documentElement.classList.toggle("dark", tokens.dark);

  // Apply semantic tokens directly as CSS custom properties
  const style = document.documentElement.style;
  style.setProperty("--theme-sidebar-bg", tokens.sidebarBg);
  style.setProperty("--theme-editor-bg", tokens.editorBg);
  style.setProperty("--theme-terminal-bg", tokens.terminalBg);
  style.setProperty("--theme-status-bar-bg", tokens.statusBarBg);
  style.setProperty("--theme-status-bar-fg", tokens.statusBarFg);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent FOUC
applyCustomTheme(getStoredThemeId());

function getSnapshot(): ThemeId {
  const id = getStoredThemeId();
  if (lastThemeId === id) return lastThemeId;
  lastThemeId = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Cross-tab sync
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyCustomTheme(getStoredThemeId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useCustomTheme(): {
  themeId: ThemeId;
  theme: BuiltInTheme;
  themes: readonly BuiltInTheme[];
  setThemeId: (id: ThemeId) => void;
} {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);

  const setThemeId = useCallback((id: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, id);
    applyCustomTheme(id, true);
    lastThemeId = id;
    emitChange();
  }, []);

  return {
    themeId,
    theme: getBuiltInTheme(themeId),
    themes: BUILT_IN_THEMES,
    setThemeId,
  };
}

