import { createContext, useContext, type ReactNode } from "react";
import { type BuiltInTheme, type ThemeId, BUILT_IN_THEMES } from "@t3tools/shared/theme";
import { useCustomTheme } from "../hooks/useCustomTheme";

interface ThemeContextValue {
  themeId: ThemeId;
  theme: BuiltInTheme;
  themes: readonly BuiltInTheme[];
  setThemeId: (id: ThemeId) => void;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const value = useCustomTheme();
  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export function useThemeContext(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    // Fallback when used outside ThemeProvider — read directly from the module singleton
    // This shouldn't happen in normal usage but avoids hard crashes.
    throw new Error("useThemeContext must be used within a ThemeProvider");
  }
  return ctx;
}

// Re-export for convenience
export { BUILT_IN_THEMES };

