import { type BuiltInTheme } from "@t3tools/shared/theme";
import { useThemeContext } from "./ThemeProvider";

function ThemeSwatch({ theme, active, onSelect }: {
  theme: BuiltInTheme;
  active: boolean;
  onSelect: () => void;
}) {
  const { tokens } = theme;

  return (
    <button
      type="button"
      role="radio"
      aria-checked={active}
      onClick={onSelect}
      className={`group relative flex flex-col overflow-hidden rounded-xl border text-left transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 ${
        active
          ? "border-primary/60 ring-2 ring-primary/30"
          : "border-border hover:border-primary/30"
      }`}
    >
      {/* Mini preview */}
      <div
        className="flex h-16 w-full overflow-hidden"
        style={{ background: tokens.background }}
        aria-hidden="true"
      >
        {/* Sidebar strip */}
        <div
          className="h-full w-8 shrink-0"
          style={{ background: tokens.sidebarBg }}
        />
        {/* Editor area */}
        <div className="flex flex-1 flex-col">
          {/* Status bar */}
          <div
            className="h-2 w-full"
            style={{ background: tokens.statusBarBg }}
          />
          {/* Editor body */}
          <div
            className="flex flex-1 items-center justify-center"
            style={{ background: tokens.editorBg }}
          >
            {/* Accent dot */}
            <div
              className="h-3 w-3 rounded-full"
              style={{ background: tokens.accent }}
            />
          </div>
          {/* Terminal strip */}
          <div
            className="h-4 w-full"
            style={{ background: tokens.terminalBg }}
          />
        </div>
      </div>

      {/* Label row */}
      <div
        className="flex items-center justify-between gap-1 px-2.5 py-2"
        style={{
          background: tokens.background,
          color: tokens.foreground,
          borderTop: `1px solid ${tokens.dark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.08)"}`,
        }}
      >
        <span className="text-xs font-medium">{theme.label}</span>
        {active ? (
          <span
            className="rounded px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wide"
            style={{
              background: `color-mix(in srgb, ${tokens.accent} 18%, transparent)`,
              color: tokens.accent,
            }}
          >
            Active
          </span>
        ) : null}
      </div>
    </button>
  );
}

export function ThemeSelector() {
  const { themeId, themes, setThemeId } = useThemeContext();

  return (
    <div
      className="grid gap-3"
      style={{ gridTemplateColumns: "repeat(auto-fill, minmax(140px, 1fr))" }}
      role="radiogroup"
      aria-label="Theme"
    >
      {themes.map((theme) => (
        <ThemeSwatch
          key={theme.id}
          theme={theme}
          active={theme.id === themeId}
          onSelect={() => setThemeId(theme.id)}
        />
      ))}
    </div>
  );
}

