   Specificity (0,2,0): :root + [data-theme="…"] beats the default :root (0,1,0)
   and the @variant dark block nested inside it, so no !important is needed.
   ─────────────────────────────────────────────────────────────────────────── */

:root[data-theme="t3-light"] {
  color-scheme: light;
  --background: #ffffff;
  --foreground: #262626;
  --card: #ffffff;
  --card-foreground: #262626;
  --popover: #ffffff;
  --popover-foreground: #262626;
  --primary: oklch(0.488 0.217 264);
  --primary-foreground: #ffffff;
  --secondary: color-mix(in srgb, #000000 4%, transparent);
  --secondary-foreground: #262626;
  --muted: color-mix(in srgb, #000000 4%, transparent);
  --muted-foreground: color-mix(in srgb, #737373 90%, #000000);
  --accent: color-mix(in srgb, #000000 4%, transparent);
  --accent-foreground: #262626;
  --destructive: #ef4444;
  --destructive-foreground: #b91c1c;
  --border: color-mix(in srgb, #000000 8%, transparent);
  --input: color-mix(in srgb, #000000 10%, transparent);
  --ring: oklch(0.488 0.217 264);
  --info: #3b82f6;
  --info-foreground: #1d4ed8;
  --success: #10b981;
  --success-foreground: #047857;
  --warning: #f59e0b;
  --warning-foreground: #b45309;
  /* Semantic theme tokens */
  --theme-sidebar-bg: #fafafa;
  --theme-editor-bg: #f5f5f5;
  --theme-terminal-bg: #f9f9f9;
  --theme-status-bar-bg: oklch(0.92 0.04 264);
